const Game2048 = () => {
  const [board, setBoard] = React.useState(null);
  const [score, setScore] = React.useState(0);
  const [best, setBest] = React.useState(() => Number(localStorage.getItem('best2048')) || 0);
  const [over, setOver] = React.useState(false);

  const getColor = (v) => {
    const colors = {
      0: '#cdc1b4', 2: '#eee4da', 4: '#ede0c8', 8: '#f2b179',
      16: '#f59563', 32: '#f67c5f', 64: '#f65e3b', 128: '#edcf72',
      256: '#edcc61', 512: '#edc850', 1024: '#edc53f', 2048: '#edc22e'
    };
    return colors[v] || '#3c3a32';
  };
  const getTextColor = (v) => v > 4 ? '#f9f6f2' : '#776e65';

  const emptyBoard = () => Array(4).fill(null).map(() => Array(4).fill(0));

  const addRandom = (b) => {
    const empty = [];
    for (let r = 0; r < 4; r++) for (let c = 0; c < 4; c++) if (!b[r][c]) empty.push([r, c]);
    if (!empty.length) return b;
    const [r, c] = empty[Math.floor(Math.random() * empty.length)];
    const nb = b.map(row => [...row]);
    nb[r][c] = Math.random() < 0.9 ? 2 : 4;
    return nb;
  };

  const init = () => {
    let b = emptyBoard();
    b = addRandom(addRandom(b));
    setBoard(b);
    setScore(0);
    setOver(false);
  };

  React.useEffect(() => {
    init();
  }, []);

  const slideRow = (row) => {
    let arr = row.filter(v => v);
    for (let i = 0; i < arr.length - 1; i++) {
      if (arr[i] === arr[i + 1]) {
        arr[i] *= 2;
        setScore(s => s + arr[i]);
        arr[i + 1] = 0;
      }
    }
    arr = arr.filter(v => v);
    while (arr.length < 4) arr.push(0);
    return arr;
  };

  const move = (dir) => {
    if (over || !board) return;
    let b = board.map(r => [...r]);
    let moved = false;

    if (dir === 'left') {
      for (let r = 0; r < 4; r++) {
        const newRow = slideRow(b[r]);
        if (newRow.some((v, i) => v !== b[r][i])) moved = true;
        b[r] = newRow;
      }
    } else if (dir === 'right') {
      for (let r = 0; r < 4; r++) {
        const newRow = slideRow(b[r].slice().reverse()).reverse();
        if (newRow.some((v, i) => v !== b[r][i])) moved = true;
        b[r] = newRow;
      }
    } else if (dir === 'up') {
      for (let c = 0; c < 4; c++) {
        const col = [b[0][c], b[1][c], b[2][c], b[3][c]];
        const newCol = slideRow(col);
        if (newCol.some((v, i) => v !== col[i])) moved = true;
        for (let r = 0; r < 4; r++) b[r][c] = newCol[r];
      }
    } else if (dir === 'down') {
      for (let c = 0; c < 4; c++) {
        const col = [b[0][c], b[1][c], b[2][c], b[3][c]];
        const newCol = slideRow(col.reverse()).reverse();
        if (newCol.some((v, i) => v !== [b[0][c], b[1][c], b[2][c], b[3][c]][i])) moved = true;
        for (let r = 0; r < 4; r++) b[r][c] = newCol[r];
      }
    }

    if (moved) {
      b = addRandom(b);
      setBoard(b);
      const hasEmpty = b.some(r => r.some(v => !v));
      const canMerge = b.some((r, i) => r.some((v, j) =>
        (j < 3 && v === b[i][j+1]) || (i < 3 && v === b[i+1][j])
      ));
      if (!hasEmpty && !canMerge) setOver(true);
    }
  };

  React.useEffect(() => {
    const handler = (e) => {
      const keys = { ArrowLeft: 'left', ArrowRight: 'right', ArrowUp: 'up', ArrowDown: 'down' };
      if (keys[e.key]) { e.preventDefault(); move(keys[e.key]); }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [board, over]);

  React.useEffect(() => {
    if (score > best) {
      setBest(score);
      localStorage.setItem('best2048', score);
    }
  }, [score]);

  if (!board) return null;

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, '2048'),
    React.createElement('div', { style: { display: 'flex', gap: '16px' } },
      React.createElement('div', { style: { textAlign: 'center' } },
        React.createElement('div', { style: { fontSize: '11px', color: '#6b7280', fontWeight: 600 } }, 'SCORE'),
        React.createElement('div', { style: { fontSize: '18px', fontWeight: 700, color: '#111827' } }, score)
      ),
      React.createElement('div', { style: { textAlign: 'center' } },
        React.createElement('div', { style: { fontSize: '11px', color: '#6b7280', fontWeight: 600 } }, 'BEST'),
        React.createElement('div', { style: { fontSize: '18px', fontWeight: 700, color: '#111827' } }, best)
      )
    ),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(4, 60px)', gap: '6px', background: '#bbada0', padding: '6px', borderRadius: '6px', position: 'relative' } },
      board.map((row, r) => row.map((cell, c) =>
        React.createElement('div', {
          key: r + '-' + c,
          style: {
            width: '60px',
            height: '60px',
            borderRadius: '4px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: cell > 512 ? '18px' : '22px',
            fontWeight: 700,
            background: getColor(cell),
            color: getTextColor(cell),
            transition: 'all 0.15s ease'
          }
        }, cell || '')
      )),
      over && React.createElement('div', { style: { position: 'absolute', inset: 0, background: 'rgba(255,255,255,0.85)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', borderRadius: '6px', gap: '8px' } },
        React.createElement('div', { style: { fontSize: '24px', fontWeight: 700, color: '#776e65' } }, 'Game Over!'),
        React.createElement('button', { onClick: init, style: { fontSize: '13px', padding: '8px 20px', borderRadius: '4px', border: 'none', background: '#8f7a66', color: '#f9f6f2', cursor: 'pointer', fontWeight: 600 } }, 'Try Again')
      )
    ),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: 'repeat(3, 40px)', gridTemplateRows: 'repeat(2, 36px)', gap: '4px' } },
      React.createElement('div'),
      React.createElement('button', { onClick: () => move('up'), style: { width: '40px', height: '36px', borderRadius: '4px', border: '1px solid #d1d5db', background: '#f3f4f6', cursor: 'pointer', fontSize: '16px' } }, '▲'),
      React.createElement('div'),
      React.createElement('button', { onClick: () => move('left'), style: { width: '40px', height: '36px', borderRadius: '4px', border: '1px solid #d1d5db', background: '#f3f4f6', cursor: 'pointer', fontSize: '16px' } }, '◀'),
      React.createElement('button', { onClick: () => move('down'), style: { width: '40px', height: '36px', borderRadius: '4px', border: '1px solid #d1d5db', background: '#f3f4f6', cursor: 'pointer', fontSize: '16px' } }, '▼'),
      React.createElement('button', { onClick: () => move('right'), style: { width: '40px', height: '36px', borderRadius: '4px', border: '1px solid #d1d5db', background: '#f3f4f6', cursor: 'pointer', fontSize: '16px' } }, '▶')
    ),
    React.createElement('button', { onClick: init, style: { fontSize: '12px', padding: '6px 14px', borderRadius: '4px', border: 'none', background: '#6b7280', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'New Game')
  );
};
render(<Game2048/>);
